20	import { REVEAL_WRITING_STYLE_INTRO } from "../../constants/messages";
21	import { EASE_OUT_QUART } from "../../constants/motion";
22	import { getCurrentProgress } from "../../state/derive";
23	import type { Action, OnboardingState } from "../../state/types";
24	import { ComposerCTA } from "../ComposerCTA";
25	import { OnboardingCTAButton } from "../OnboardingCTAButton";
26	import { RevealIntroBubble } from "../RevealIntroBubble";
27	import { WritingStyleRevealCard } from "../reveal/WritingStyleRevealCard";
28	
29	interface RevealWritingStyleProps {
30	  state: OnboardingState;
31	  dispatch: Dispatch<Action>;
32	}
33	
34	export function RevealWritingStyle({ state }: { state: OnboardingState }) {
35	  const writingStyle = state.server?.writing_style;
36	  const profession = state.responses[FIELD_NAMES.PROFESSION] ?? "";
37	
38	  if (!writingStyle?.style_summary) return null;
39	
40	  return (
41	    <div className="mt-3 space-y-4">
42	      {state.ackedWritingStyle ? (
43	        <CollapsedWritingStyle>
44	          <WritingStyleRevealCard
45	            style_summary={writingStyle.style_summary}
46	            example={writingStyle.example ?? null}
47	            profession={profession}
48	            embedded
49	          />
50	        </CollapsedWritingStyle>
51	      ) : (
52	        <RevealIntroBubble text={REVEAL_WRITING_STYLE_INTRO}>
53	          <WritingStyleRevealCard
54	            style_summary={writingStyle.style_summary}
55	            example={writingStyle.example ?? null}
56	            profession={profession}
57	          />
58	        </RevealIntroBubble>
59	      )}
60	
61	      <AnimatePresence>
62	        {state.ackedWritingStyle && (
63	          <m.div
64	            key="waiting"
65	            className="space-y-3"
66	            initial={{ opacity: 0, y: 12 }}
67	            animate={{ opacity: 1, y: 0 }}
68	            transition={{ duration: 0.4, ease: EASE_OUT_QUART, delay: 0.1 }}
69	          >
70	            <ChatBubbleBot
71	              {...BOT_BUBBLE_DEFAULTS}
72	              text="Looking for things I can help with..."
73	            >
74	              <div className="mt-2 ml-10.75 flex items-center gap-2">
75	                <Spinner size="sm" color="default" />
76	                <span className="text-sm text-zinc-500">
77	                  {getCurrentProgress(state) ?? "Almost ready"}
78	                </span>
79	              </div>
80	            </ChatBubbleBot>
81	          </m.div>
82	        )}
83	      </AnimatePresence>
84	    </div>
85	  );
86	}
87	
88	interface CollapsedWritingStyleProps {
89	  children: React.ReactNode;
90	}
91	
92	function CollapsedWritingStyle({ children }: CollapsedWritingStyleProps) {
93	  return (
94	    <m.div
95	      className="ml-10.75 w-96 rounded-2xl bg-zinc-800/40 p-1 backdrop-blur-xl"
96	      initial={{ opacity: 0, y: 8 }}
97	      animate={{ opacity: 1, y: 0 }}
98	      transition={{ duration: 0.35, ease: EASE_OUT_QUART }}
99	    >
100	      <Accordion
101	        variant="light"
102	        className="px-0"
103	        itemClasses={{
104	          base: "px-0",
105	          trigger: "px-3 py-2 rounded-2xl data-[hover=true]:bg-zinc-700/40",
106	          titleWrapper: "py-0",
107	          content: "px-3 pt-2 pb-3",
