123	        </AccordionItem>
124	      </Accordion>
125	    </m.div>
126	  );
127	}
128	
129	export function RevealWritingStyleComposer({
130	  state,
131	  dispatch,
132	}: RevealWritingStyleProps) {
133	  if (state.ackedWritingStyle) return null;
134	  if (!state.server?.writing_style?.style_summary) return null;
135	
136	  return (
137	    <ComposerCTA>
